export type SystemPlugin = { accounts: SystemPluginAccounts; instructions: SystemPluginInstructions };

export type SystemPluginAccounts = { nonce: ReturnType<typeof getNonceCodec> & SelfFetchFunctions<NonceArgs, Nonce> };

